import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";
  private static readonly TARGET_EMAIL = "carlos.silva@industriasnb.com.br";

  private static async convertImageToPdf(file: File): Promise<File> {
    try {
      // Importação dinâmica para evitar peso no bundle inicial
      const { jsPDF } = await import('https://esm.sh/jspdf');

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            const doc = new jsPDF({
              orientation: img.width > img.height ? 'landscape' : 'portrait',
              unit: 'px',
              format: [img.width, img.height]
            });

            doc.addImage(img, 'JPEG', 0, 0, img.width, img.height);
            const pdfBlob = doc.output('blob');
            const pdfFileName = file.name.replace(/\.[^/.]+$/, "") + ".pdf";

            resolve(new File([pdfBlob], pdfFileName, {
              type: 'application/pdf',
              lastModified: Date.now()
            }));
          };
          img.onerror = () => reject(new Error("Erro na imagem"));
          img.src = e.target?.result as string;
        };
        reader.readAsDataURL(file);
      });
    } catch (err) {
      throw err;
    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();
      formData.append("access_key", this.WEB3FORMS_KEY);
      formData.append("to", this.TARGET_EMAIL); // Direcionamento solicitado
      formData.append("subject", `[CTNB PORTAL] NOVO LEAD: ${data.nome_completo.toUpperCase()}`);
      formData.append("from_name", "Portal de Dados CTNB");
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);
      formData.append("empresa", data.empresa || "Não informada");
      formData.append("revendedor", data.revendedor);
      formData.append("telefone", data.telefone);

      let attachment = data.documento;
      if (attachment && attachment.type.startsWith('image/')) {
        try {
          attachment = await this.convertImageToPdf(attachment);
        } catch (e) {
          console.error("Erro PDF:", e);
        }
      }

      if (attachment) formData.append("attachment", attachment);

      const message = `
        LEAD CAPTURADO PELO PORTAL OFICIAL
        ----------------------------------
        Nome: ${data.nome_completo}
        E-mail: ${data.email}
        Telefone: ${data.telefone}
        Revendedor: ${data.revendedor}
        Empresa: ${data.empresa || 'Não informada'}

        Destinatário: ${this.TARGET_EMAIL}
      `;
      formData.append("message", message);

      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData,
      });

      const result = await response.json();
      return {
        success: result.success,
        message: result.success ? "Encaminhado com sucesso" : "Erro no servidor"
      };
    } catch (error) {
      return { success: false, message: "Erro de conexão" };
    }
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { LeadData, FormErrors, FormStatus } from '../types';
import { LeadService } from '../services/leadService';
import LeadReview from './LeadReview';

interface LeadFormProps {
  onSuccess: (data: LeadData) => void;
}

const LeadForm: React.FC<LeadFormProps> = ({ onSuccess }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState<LeadData>({
    nome_completo: '',
    empresa: '',
    email: '',
    telefone: '',
    revendedor: '',
    documento: null,
    aceite_privacidade: false
  });

  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [errors, setErrors] = useState<FormErrors>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [status, setStatus] = useState<FormStatus>(FormStatus.IDLE);
  const [shakeField, setShakeField] = useState<string | null>(null);

  useEffect(() => {
    return () => { if (previewUrl) URL.revokeObjectURL(previewUrl); };
  }, [previewUrl]);

  const validateField = useCallback((name: string, value: any) => {
    let error = '';
    switch (name) {
      case 'nome_completo':
        const val = String(value).trim();
        if (!val) error = 'Obrigatório';
        else if (val.split(/\s+/).length < 2) error = 'Nome e Sobrenome';
        break;
      case 'email':
        if (!value.trim()) error = 'Obrigatório';
        else if (!LeadService.validateEmail(value)) error = 'E-mail inválido';
        break;
      case 'telefone':
        if (!value.replace(/\D/g, '')) error = 'Obrigatório';
        else if (value.replace(/\D/g, '').length < 10) error = 'Incompleto';
        break;
      case 'documento':
        if (!value) error = 'Obrigatório';
        break;
      case 'revendedor':
        if (!value) error = 'Selecione';
        break;
      case 'aceite_privacidade':
        if (!value) error = 'Obrigatório';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return !error;
  }, []);

  const isFormValid = useMemo(() => {
    return (
      formData.nome_completo.trim().split(/\s+/).length >= 2 &&
      LeadService.validateEmail(formData.email) &&
      formData.telefone.replace(/\D/g, '').length >= 10 &&
      formData.revendedor !== '' &&
      formData.documento !== null &&
      formData.aceite_privacidade
    );
  }, [formData]);

  const handleReviewRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (isFormValid) setStatus(FormStatus.REVIEW);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      setPreviewUrl(URL.createObjectURL(file));
      setFormData(p => ({ ...p, documento: file }));
      validateField('documento', file);
    }
  };

  const inputClasses = (name: string) => `
    w-full px-4 py-3.5 rounded-2xl border-2 transition-all duration-300 outline-none text-sm font-semibold
    ${touched[name] && errors[name] 
      ? 'border-red-200 bg-red-50 text-red-900 focus:border-red-400' 
      : 'border-slate-50 bg-slate-50 focus:border-[#001b3a] text-slate-700'}
  `;

  return (
    <>
      <form onSubmit={handleReviewRequest} className="space-y-4" noValidate>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
            Nome Completo
            {touched.nome_completo && errors.nome_completo && <span className="text-red-500 lowercase">{errors.nome_completo}</span>}
          </label>
          <input 
            name="nome_completo" 
            value={formData.nome_completo} 
            onChange={(e) => {setFormData(p => ({...p, nome_completo: e.target.value})); validateField('nome_completo', e.target.value)}}
            onBlur={() => setTouched(t => ({...t, nome_completo: true}))}
            placeholder="Nome e Sobrenome" className={inputClasses('nome_completo')} 
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone</label>
            <input 
              name="telefone" 
              value={formData.telefone} 
              onChange={(e) => setFormData(p => ({...p, telefone: e.target.value}))}
              onBlur={() => setTouched(t => ({...t, telefone: true}))}
              placeholder="(00) 00000-0000" className={inputClasses('telefone')} 
            />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail</label>
            <input 
              name="email" 
              type="email"
              value={formData.email} 
              onChange={(e) => setFormData(p => ({...p, email: e.target.value}))}
              onBlur={() => setTouched(t => ({...t, email: true}))}
              placeholder="seu@email.com" className={inputClasses('email')} 
            />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Documento (Foto)</label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`w-full h-32 rounded-3xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all overflow-hidden ${previewUrl ? 'border-emerald-400' : 'border-slate-100 bg-slate-50'}`}
          >
            {previewUrl ? (
              <img src={previewUrl} className="h-full w-auto object-contain" alt="Preview" />
            ) : (
              <span className="text-[9px] font-black text-slate-400 uppercase">Tocar para capturar</span>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" capture="environment" className="hidden" />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Revendedor</label>
          <div className="flex gap-2">
            {['JF', 'Nogueira'].map(r => (
              <button 
                key={r} type="button"
                onClick={() => setFormData(p => ({...p, revendedor: r as any}))}
                className={`flex-1 py-4 rounded-xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${formData.revendedor === r ? 'bg-[#001b3a] border-[#001b3a] text-white' : 'border-slate-50 text-slate-400'}`}
              >
                {r}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-start gap-3 p-4 bg-slate-50 rounded-2xl">
          <input 
            type="checkbox" id="aceite" checked={formData.aceite_privacidade}
            onChange={(e) => setFormData(p => ({...p, aceite_privacidade: e.target.checked}))}
            className="w-5 h-5 rounded text-emerald-600"
          />
          <label htmlFor="aceite" className="text-[9px] text-slate-500 font-medium">Aceito os termos de privacidade para envio às Indústrias NB.</label>
        </div>

        <button 
          type="submit" 
          disabled={!isFormValid}
          className={`w-full py-5 rounded-3xl font-black text-xs uppercase tracking-widest transition-all
            ${isFormValid 
              ? 'bg-[#001b3a] text-white shadow-xl active:scale-95 cursor-pointer' 
              : 'bg-slate-100 text-slate-300 cursor-not-allowed'}
          `}
        >
          {isFormValid ? 'Revisar e Enviar' : 'Preencha todos os campos'}
        </button>
      </form>

      {(status === FormStatus.REVIEW || status === FormStatus.SUBMITTING) && (
        <LeadReview 
          data={formData} 
          onConfirm={async () => {
            if (status === FormStatus.SUBMITTING) return;
            setStatus(FormStatus.SUBMITTING);
            const res = await LeadService.submitLead(formData);
            if (res.success) onSuccess(formData);
            else setStatus(FormStatus.ERROR);
          }} 
          onEdit={() => setStatus(FormStatus.IDLE)} 
          isSubmitting={status === FormStatus.SUBMITTING}
        />
      )}
    </>
  );
};

export default LeadForm;

