export class LeadService {
  // Configuração do destinatário solicitado
  private static readonly RECIPIENT_EMAIL = "carlos.silva@industriasnb.com.br";
  // Endpoint genérico para sua API de backend
  private static readonly API_ENDPOINT = "/api/encaminhar-lead";

  private static async convertImageToPdf(file: File): Promise<File> {
    try {
      const { jsPDF } = await import('https://esm.sh/jspdf');

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            const doc = new jsPDF({
              orientation: img.width > img.height ? 'landscape' : 'portrait',
              unit: 'px',
              format: [img.width, img.height]
            });

            doc.addImage(img, 'JPEG', 0, 0, img.width, img.height);
            const pdfBlob = doc.output('blob');
            const pdfFileName = file.name.replace(/\.[^/.]+$/, "") + ".pdf";

            resolve(new File([pdfBlob], pdfFileName, {
              type: 'application/pdf',
              lastModified: Date.now()
            }));
          };
          img.onerror = () => reject(new Error("Erro ao processar imagem"));
          img.src = e.target?.result as string;
        };
        reader.readAsDataURL(file);
      });
    } catch (err) {
      throw err;
    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // Metadados de roteamento de e-mail
      formData.append("destinatario", this.RECIPIENT_EMAIL);
      formData.append("assunto", `CADASTRO CTNB: ${data.nome_completo.toUpperCase()}`);

      // Dados do Lead
      formData.append("nome", data.nome_completo);
      formData.append("email", data.email);
      formData.append("telefone", data.telefone);
      formData.append("revendedor", data.revendedor);
      formData.append("empresa", data.empresa || "Não informada");

      let finalDocument = data.documento;
      if (finalDocument && finalDocument.type.startsWith('image/')) {
        try {
          finalDocument = await this.convertImageToPdf(finalDocument);
        } catch (e) {
          console.warn("Enviando imagem original pois conversão PDF falhou.");
        }
      }

      if (finalDocument) {
        formData.append("documento_pdf", finalDocument);
      }

      // Simulação de envio para o seu backend
      // Em produção, descomente a linha abaixo:
      // const response = await fetch(this.API_ENDPOINT, { method: "POST", body: formData });

      // Simulação de delay de rede para UX
      await new Promise(resolve => setTimeout(resolve, 2000));

      return {
        success: true,
        message: "Dados encaminhados para a fila de processamento das Indústrias NB."
      };
    } catch (error) {
      return {
        success: false,
        message: "Erro ao conectar com o serviço de encaminhamento."
      };
    }
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

