    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // Configuração Web3Forms
      formData.append("access_key", this.ACCESS_KEY);
      formData.append("to", this.TARGET_EMAIL);
      formData.append("from_name", "Portal CTNB");
      formData.append("subject", `NOVO LEAD CTNB: ${data.nome_completo.toUpperCase()}`);

      // Mapeamento de dados conforme solicitado no snippet
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);

      // Montagem da mensagem detalhada
      const message = `
NOVO CADASTRO RECEBIDO PELO PORTAL CTNB
---------------------------------------
Nome: ${data.nome_completo}
E-mail: ${data.email}
Telefone: ${data.telefone}
Revendedor Selecionado: ${data.revendedor}
Empresa: ${data.empresa || 'Não informada'}

Este lead autorizou o envio dos dados via portal oficial.
      `;
      formData.append("message", message);

      // Processamento do anexo
      let attachment = data.documento;
      if (attachment && attachment.type.startsWith('image/')) {
        try {
          attachment = await this.convertImageToPdf(attachment);
        } catch (e) {
          console.warn("Falha na conversão PDF, enviando arquivo original.");
        }
      }

      if (attachment) {
        formData.append("attachment", attachment);
      }

      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData,
      });

      const result = await response.json();

      if (result.success) {
        return {
          success: true,
          message: "Dados encaminhados com sucesso para as Indústrias NB."
        };
      } else {
        return {
          success: false,
          message: result.message || "Erro ao processar envio no servidor."
        };
      }
    } catch (error) {
      return {
        success: false,
        message: "Erro de conexão. Verifique sua internet."
      };
    }
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
