        <button 
          type="submit" 
          disabled={!isFormValid}
          className={`w-full py-5 rounded-3xl font-black text-xs uppercase tracking-[0.2em] transition-all shadow-2xl
            ${isFormValid 
              ? 'bg-[#001b3a] text-white shadow-blue-900/20 active:scale-95 cursor-pointer' 
              : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'}
          `}
        >
          {isFormValid ? 'Revisar e Enviar' : 'Complete o Formulário'}
        </button>
      </form>

      {(status === FormStatus.REVIEW || status === FormStatus.SUBMITTING) && (
        <LeadReview 
          data={formData} 
          onConfirm={async () => {
            if (status === FormStatus.SUBMITTING) return;
            setStatus(FormStatus.SUBMITTING);
            const res = await LeadService.submitLead(formData);
            if (res.success) onSuccess(formData);
            else setStatus(FormStatus.ERROR);
          }} 
          onEdit={() => setStatus(FormStatus.IDLE)} 
          isSubmitting={status === FormStatus.SUBMITTING}
        />
      )}
    </>
  );
};

