import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  // Chave fornecida pelo usuário
  private static readonly ACCESS_KEY = "6c05bf52-c51c-417a-b60a-3e791c5d9cb0";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Tenta converter a imagem para PDF. 
   * Se falhar (por rede ou suporte), retorna o arquivo original.
   */
  private static async convertImageToPdf(file: File): Promise<File> {
    try {
      // Importação dinâmica para não travar o bundle inicial
      const { jsPDF } = await import('https://esm.sh/jspdf');

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            // Cria PDF nas dimensões da imagem
            const doc = new jsPDF({
              orientation: img.width > img.height ? 'landscape' : 'portrait',
              unit: 'px',
              format: [img.width, img.height]
            });

            doc.addImage(img, 'JPEG', 0, 0, img.width, img.height);
            const pdfBlob = doc.output('blob');
            const pdfFileName = file.name.replace(/\.[^/.]+$/, "") + ".pdf";

            resolve(new File([pdfBlob], pdfFileName, {
              type: 'application/pdf',
              lastModified: Date.now()
            }));
          };
          img.onerror = () => reject(new Error("Erro ao carregar imagem para conversão"));
          img.src = e.target?.result as string;
        };
        reader.onerror = () => reject(new Error("Erro na leitura do arquivo"));
        reader.readAsDataURL(file);
      });
    } catch (err) {
      console.warn("Conversão para PDF indisponível ou falhou. Enviando original.", err);
      // Retorna o arquivo original para não interromper o fluxo
      return file;
    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // 1. Configuração Obrigatória
      formData.append("access_key", this.ACCESS_KEY);

      // NOTA: Removemos "to" e "from_name" pois o Web3Forms bloqueia 
      // o envio se a chave não for PRO. O destino é o email dono da chave.
      formData.append("subject", `Novo Lead CTNB: ${data.nome_completo}`);

      // 2. Mapeamento de Campos (exatamente como no formulário HTML padrão)
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);

      // 3. Construção da Mensagem
      const messageContent = `
DADOS DO LEAD - PORTAL CTNB
===========================
Nome: ${data.nome_completo}
Email: ${data.email}
Telefone: ${data.telefone}
Revendedor: ${data.revendedor}
Empresa: ${data.empresa || 'Não informada'}

* Aceite de privacidade confirmado pelo usuário.
      `;
      formData.append("message", messageContent.trim());

      // 4. Processamento de Anexo (Imagem -> PDF ou Original)
      if (data.documento) {
        let fileToSend = data.documento;

        // Tenta converter apenas se for imagem
        if (fileToSend.type.startsWith('image/')) {
          try {
            fileToSend = await this.convertImageToPdf(fileToSend);
          } catch (e) {
            // Silenciosamente falha para o original
          }
        }

        // O campo deve ser "attachment" para o Web3Forms
        formData.append("attachment", fileToSend);
      }

      // 5. Envio
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData,
        // Não definir Content-Type manualmente com FormData, o browser faz isso.
      });

      const result = await response.json();

      if (response.ok && result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!"
        };
      } else {
        console.error("Erro Web3Forms:", result);
        return {
          success: false,
          message: result.message || "Erro ao processar envio."
        };
      }

    } catch (error) {
      console.error("Erro de Rede:", error);
      return {
        success: false,
        message: "Erro de conexão. Verifique sua internet."
      };
    }
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

