  private static async convertImageToPdf(file: File): Promise<File> {
    try {
      // Acessa o jsPDF do escopo global (injetado via script tag no index.html)
      const jspdfLib = (window as any).jspdf;

      if (!jspdfLib) {
        console.warn("Biblioteca jsPDF não carregada. Enviando imagem original.");
        return file;
      }

      const { jsPDF } = jspdfLib;

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            // Cria PDF
            const doc = new jsPDF({
              orientation: img.width > img.height ? 'landscape' : 'portrait',
              unit: 'px',
              format: [img.width, img.height]
            });

            doc.addImage(img, 'JPEG', 0, 0, img.width, img.height);
            const pdfBlob = doc.output('blob');
            const pdfFileName = file.name.replace(/\.[^/.]+$/, "") + ".pdf";

            resolve(new File([pdfBlob], pdfFileName, {
              type: 'application/pdf',
              lastModified: Date.now()
            }));
          };
          img.onerror = () => reject(new Error("Falha ao carregar imagem"));
          img.src = e.target?.result as string;
        };
        reader.onerror = () => reject(new Error("Falha ao ler arquivo"));
        reader.readAsDataURL(file);
      });
    } catch (err) {
      console.warn("Erro na conversão PDF:", err);
      return file;
    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // 1. Chave de acesso
      formData.append("access_key", this.ACCESS_KEY);

      // 2. Campo anti-spam (botcheck) - deve ser vazio
      formData.append("botcheck", "");

      // 3. Dados do formulário
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);
      formData.append("subject", `Novo Lead: ${data.nome_completo}`); // Subject simplificado

      const messageContent = `
NOVO LEAD RECEBIDO
------------------
Nome: ${data.nome_completo}
Email: ${data.email}
Telefone: ${data.telefone}
Revendedor: ${data.revendedor}
Empresa: ${data.empresa || 'N/A'}

Status: Validado e Aceite LGPD Confirmado.
      `;
      formData.append("message", messageContent.trim());

      // 4. Anexo
      if (data.documento) {
        let fileToSend = data.documento;
        if (fileToSend.type.startsWith('image/')) {
          try {
            fileToSend = await this.convertImageToPdf(fileToSend);
          } catch (e) {
            // Mantém arquivo original se falhar
          }
        }
        formData.append("attachment", fileToSend);
      }

      // 5. Envio com Header JSON explícito
      // O header 'Accept' é CRUCIAL para evitar que o Web3Forms retorne um redirect 302
      // que quebraria o fluxo da aplicação React.
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        headers: {
          'Accept': 'application/json'
        },
        body: formData
      });

      const result = await response.json();

      if (response.ok && result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!"
        };
      } else {
        console.error("Erro Web3Forms:", result);
        return {
          success: false,
          message: result.message || "Erro no envio."
        };
      }
    } catch (error) {
      console.error("Erro de conexão:", error);
      return {
        success: false,
        message: "Erro de conexão. Tente novamente."
      };
    }
  }

  static validateEmail(email: string): boolean {
