import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly ACCESS_KEY = "6c05bf52-c51c-417a-b60a-3e791c5d9cb0";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // 1. Configuração Básica
      formData.append("access_key", this.ACCESS_KEY);
      formData.append("botcheck", ""); // Anti-spam oculto

      // 2. Dados do Formulário
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);
      // Assunto limpo para garantir entrega
      formData.append("subject", `Novo Lead: ${data.nome_completo} - via Portal CTNB`);

      // 3. Mensagem Formatada
      const messageContent = `
PORTAL CTNB - DADOS RECEBIDOS
=============================
Nome: ${data.nome_completo}
Email: ${data.email}
Telefone: ${data.telefone}
Revendedor Indicado: ${data.revendedor}
Empresa: ${data.empresa || 'Não informada'}

Data do Envio: ${new Date().toLocaleString('pt-BR')}
Status: Aceite de Privacidade Confirmado.
      `;
      formData.append("message", messageContent.trim());

      // 4. Anexo com Sanitização de Nome (Crítico para evitar rejeição)
      if (data.documento) {
        const file = data.documento;
        const extension = file.name.split('.').pop() || 'jpg';
        // Renomeia para algo seguro (ex: anexo-1715000000.jpg)
        const safeFileName = `anexo-${Date.now()}.${extension}`;

        // Passamos o terceiro argumento (filename) para o FormData
        formData.append("attachment", file, safeFileName);
      }

      // 5. Configuração de Timeout e Fetch
      // Adicionamos um timeout de 30s para não deixar o usuário esperando eternamente em conexões ruins
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000);

      try {
        const response = await fetch(this.API_ENDPOINT, {
          method: "POST",
          headers: {
            // Header CRUCIAL para evitar redirects
            'Accept': 'application/json'
          },
          body: formData,
          signal: controller.signal
        });

        clearTimeout(timeoutId);

        // Tenta parsear JSON mesmo se status for erro, para ler a mensagem do servidor
        const result = await response.json().catch(() => ({ message: "Erro desconhecido ao ler resposta." }));

        if (response.ok && result.success) {
          return {
            success: true,
            message: "Enviado com sucesso!"
          };
        } else {
          console.error("Erro Web3Forms:", result);
          return {
            success: false,
            message: result.message || "Servidor rejeitou o envio. Tente novamente."
          };
        }

      } catch (networkError: any) {
        clearTimeout(timeoutId);
        if (networkError.name === 'AbortError') {
           return { success: false, message: "Tempo limite excedido. Sua conexão está lenta." };
        }
        throw networkError;
      }

    } catch (error) {
      console.error("Erro Geral:", error);
      return {
        success: false,
        message: "Erro de conexão. Verifique sua internet e tente novamente."
      };
    }
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

