          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Foto do Documento *</label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`w-full h-32 rounded-3xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all overflow-hidden ${
              fileError ? 'border-red-300 bg-red-50' : 
              previewUrl ? 'border-emerald-400 bg-emerald-50' : 'border-slate-100 bg-slate-50'
            }`}
          >
            {previewUrl ? (
              <img src={previewUrl} className="h-full w-auto object-contain" alt="Preview" />
            ) : (
              <div className="flex flex-col items-center gap-1">
                {fileError ? (
                  <>
                    <svg className="w-6 h-6 text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg>
                    <span className="text-[9px] font-black text-red-400 uppercase text-center px-4">{fileError}</span>
                  </>
                ) : (
                  <>
                    <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><circle cx="12" cy="13" r="3" strokeWidth="2.5" /></svg>
                    <span className="text-[9px] font-black text-slate-400 uppercase">Tocar para capturar</span>
                  </>
                )}
              </div>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" capture="environment" className="hidden" />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Revendedor *</label>
          <div className="flex gap-2">
            {['JF', 'Nogueira'].map(r => (
              <button 
                key={r} type="button"
                onClick={() => setFormData(p => ({...p, revendedor: r as any}))}
                className={`flex-1 py-4 rounded-xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${formData.revendedor === r ? 'bg-[#001b3a] border-[#001b3a] text-white shadow-md' : 'border-slate-50 text-slate-400 bg-slate-50'}`}
              >
                {r}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-start gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
          <input 
            type="checkbox" id="aceite" 
            checked={formData.aceite_privacidade}
            onChange={(e) => setFormData(p => ({...p, aceite_privacidade: e.target.checked}))}
            className="w-5 h-5 rounded text-emerald-600 mt-0.5"
          />
          <label htmlFor="aceite" className="text-[9px] text-slate-500 font-medium leading-tight cursor-pointer">
            Autorizo o encaminhamento seguro via Web3Forms para <span className="font-bold text-slate-700">carlos.silva@industriasnb.com.br</span>.
          </label>
        </div>

        <button 
          type="submit" 
          disabled={!isFormValid}
          className={`w-full py-5 rounded-3xl font-black text-xs uppercase tracking-[0.2em] transition-all shadow-2xl
            ${isFormValid 
              ? 'bg-[#001b3a] text-white shadow-blue-900/20 active:scale-95 cursor-pointer' 
              : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'}
          `}
        >
          {isFormValid ? 'Revisar e Enviar' : 'Complete o Formulário'}
        </button>
      </form>

      {(status === FormStatus.REVIEW || status === FormStatus.SUBMITTING) && (
        <LeadReview 
          data={formData} 
          onConfirm={async () => {
            if (status === FormStatus.SUBMITTING) return;
            setStatus(FormStatus.SUBMITTING);
            const res = await LeadService.submitLead(formData);
            if (res.success) onSuccess(formData);
            else {
              setStatus(FormStatus.ERROR);
              // Opcional: alerta simples para feedback imediato em caso de erro
              alert(res.message);
            }
          }} 
          onEdit={() => setStatus(FormStatus.IDLE)} 
          isSubmitting={status === FormStatus.SUBMITTING}
        />
      )}
    </>
  );
};

