import { LeadData, IntegrationResponse } from '../types';

/**
 * LeadService gerencia a integração com Web3Forms e validações.
 */
export class LeadService {
  // Mantida a chave original do arquivo fornecido
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Envia os dados para o Web3Forms usando FormData.
   * Modificado para envio direto de imagem (sem conversão PDF) para estabilidade.
   */
  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // 1. Configuração Obrigatória
      formData.append("access_key", this.WEB3FORMS_KEY);
      formData.append("botcheck", ""); // Honeypot

      // NOTA: 'from_name' removido pois pode causar bloqueio em planos gratuitos se o domínio não for verificado.
      // O remetente será gerenciado pelo Web3Forms.

      formData.append("subject", `NOVO LEAD (${data.revendedor}): ${data.nome_completo.toUpperCase()}`);
      formData.append("name", data.nome_completo);
      formData.append("email", data.email);

      // Campos personalizados enviados como texto extra ou campos ocultos se suportado
      formData.append("empresa", data.empresa || "Não informada");
      formData.append("revendedor", data.revendedor);
      formData.append("telefone", data.telefone);

      // 2. Construção da Mensagem Formatada
      const messageContent = `
DADOS DO LEAD - PORTAL CTNB
===========================
Nome: ${data.nome_completo}
Email: ${data.email}
Telefone: ${data.telefone}
Revendedor Indicado: ${data.revendedor}
Empresa: ${data.empresa || 'Não informada'}
Link WhatsApp: https://wa.me/55${data.telefone.replace(/\D/g, '')}

Status: Validado e Aceite LGPD Confirmado.
      `;
      formData.append("message", messageContent.trim());

      // 3. Processamento de Anexo (Envio direto com sanitização)
      if (data.documento) {
        const file = data.documento;
        const extension = file.name.split('.').pop() || 'jpg';
        // Renomeia para evitar caracteres especiais que quebram o upload
        const safeFileName = `doc-${Date.now()}.${extension}`;

        formData.append("attachment", file, safeFileName);
      }

      // 4. Configuração de Timeout (30 segundos)
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000);

      try {
        const response = await fetch(this.API_ENDPOINT, {
          method: "POST",
          headers: {
            // Header CRUCIAL para evitar redirects e receber JSON
            'Accept': 'application/json'
          },
          body: formData,
          signal: controller.signal
        });

        clearTimeout(timeoutId);

        const result = await response.json();

        if (response.ok && result.success) {
          return {
            success: true,
            message: "Dados encaminhados com sucesso.",
            integrationId: result.id
          };
        } else {
          console.error("[SISTEMA] Erro Web3Forms:", result);
          return {
            success: false,
            message: result.message || "Erro ao processar envio no servidor."
          };
        }
      } catch (networkError: any) {
        clearTimeout(timeoutId);
        if (networkError.name === 'AbortError') {
           return { success: false, message: "Tempo limite excedido. Sua conexão está lenta." };
        }
        throw networkError;
      }

    } catch (error) {
      console.error("[SISTEMA] Falha crítica:", error);
      return {
        success: false,
        message: "Falha de conexão. Verifique sua internet."
      };
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  }
}

import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { LeadData, FormErrors, FormStatus } from '../types';
import { LeadService } from '../services/leadService';
import LeadReview from './LeadReview';

interface LeadFormProps {
  onSuccess: (data: LeadData) => void;
}

const LeadForm: React.FC<LeadFormProps> = ({ onSuccess }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const honeypotRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<LeadData>({
    nome_completo: '',
    empresa: '',
    email: '',
    telefone: '',
    revendedor: '',
    documento: null,
    aceite_privacidade: false
  });

  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [errors, setErrors] = useState<FormErrors>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [status, setStatus] = useState<FormStatus>(FormStatus.IDLE);
  const [shakeField, setShakeField] = useState<string | null>(null);

  // Novo estado para erro específico de arquivo
  const [fileError, setFileError] = useState<string | null>(null);

  // Cleanup da URL de preview para evitar vazamento de memória
  useEffect(() => {
    return () => {
      if (previewUrl) URL.revokeObjectURL(previewUrl);
    };
  }, [previewUrl]);

  const validateField = useCallback((name: string, value: any) => {
    let error = '';
    switch (name) {
      case 'nome_completo':
        const nameValue = String(value).trim();
        const parts = nameValue.split(/\s+/);
        if (nameValue.length > 0) {
          if (nameValue.length < 5) error = 'Nome muito curto';
          else if (parts.length < 2 || parts[1].length < 2) error = 'Falta o sobrenome';
        } else error = 'Obrigatório';
        break;
      case 'email':
        if (!value.trim()) error = 'Obrigatório';
        else if (!LeadService.validateEmail(value)) error = 'E-mail inválido';
        break;
      case 'telefone':
        const cleanPhone = value.replace(/\D/g, '');
        if (!cleanPhone) error = 'Obrigatório';
        else if (cleanPhone.length < 10) error = 'Telefone incompleto';
        break;
      case 'documento':
        if (!value) error = 'Foto obrigatória';
        break;
      case 'revendedor':
        if (!value) error = 'Selecione um';
        break;
      case 'aceite_privacidade':
        if (!value) error = 'Aceite obrigatório';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return !error;
  }, []);

  const applyPhoneMask = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 2) return numbers;
    if (numbers.length <= 6) return `(${numbers.slice(0, 2)}) ${numbers.slice(2)}`;
    if (numbers.length <= 10) return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 6)}-${numbers.slice(6)}`;
    return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 7)}-${numbers.slice(7, 11)}`;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    let newValue: any = type === 'checkbox' ? checked : value;
    if (name === 'telefone') newValue = applyPhoneMask(value);

    setFormData(prev => ({ ...prev, [name]: newValue }));
    if (touched[name]) validateField(name, newValue);
  };

  const handleBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    validateField(name, value);
  };

  const isFormValid = useMemo(() => {
    const nameParts = formData.nome_completo.trim().split(/\s+/);
    return (
      nameParts.length >= 2 && 
      formData.nome_completo.trim().length >= 5 &&
      LeadService.validateEmail(formData.email) &&
      formData.telefone.replace(/\D/g, '').length >= 10 &&
      formData.revendedor !== '' &&
      formData.documento !== null &&
      formData.aceite_privacidade
    );
  }, [formData]);

  const triggerShake = (fieldName: string) => {
    setShakeField(fieldName);
    setTimeout(() => setShakeField(null), 400);
  };

  const handleReviewRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (honeypotRef.current?.value) return;

    const allFields = ['nome_completo', 'email', 'telefone', 'documento', 'revendedor', 'aceite_privacidade'];
    let firstError = '';

    allFields.forEach(f => {
      setTouched(prev => ({ ...prev, [f]: true }));
      const isValid = validateField(f, formData[f as keyof LeadData]);
      if (!isValid && !firstError) firstError = f;
    });

    if (isFormValid) {
      setStatus(FormStatus.REVIEW);
    } else if (firstError) {
      triggerShake(firstError);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    setFileError(null);

    if (file) {
      // Validação de Tamanho (Máximo 5MB)
      if (file.size > 5 * 1024 * 1024) {
        setFileError("Arquivo muito grande (Máx 5MB).");
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
      }

      if (previewUrl) URL.revokeObjectURL(previewUrl);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setFormData(p => ({ ...p, documento: file }));
      setTouched(prev => ({ ...prev, documento: true }));
      validateField('documento', file);
    }
  };

  const clearFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
    setFormData(p => ({ ...p, documento: null }));
    setFileError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    validateField('documento', null);
  };

  const inputClasses = (name: string) => `
    w-full px-4 py-3.5 rounded-2xl border-2 transition-all duration-300 outline-none text-sm font-semibold
    ${touched[name] && errors[name] 
      ? 'border-red-200 bg-red-50 text-red-900 focus:border-red-400' 
      : touched[name] && !errors[name] && formData[name as keyof LeadData]
        ? 'border-emerald-100 bg-emerald-50/20 focus:border-[#001b3a]'
        : 'border-slate-50 bg-slate-50 focus:border-[#001b3a] focus:bg-white text-slate-700'}
    ${shakeField === name ? 'animate-shake' : ''}
    disabled:opacity-50
  `;

  return (
    <>
      <form onSubmit={handleReviewRequest} className="space-y-4" noValidate>
        <input type="text" ref={honeypotRef} className="hidden" tabIndex={-1} autoComplete="off" />

        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
            Nome Completo
            {touched.nome_completo && errors.nome_completo && <span className="text-red-500 lowercase font-bold">{errors.nome_completo}</span>}
          </label>
          <input 
            name="nome_completo" 
            value={formData.nome_completo} 
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder="Nome e Sobrenome" 
            className={inputClasses('nome_completo')} 
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
              Telefone
              {touched.telefone && errors.telefone && <span className="text-red-500 lowercase font-bold">Obrigatório</span>}
            </label>
            <input 
              type="tel" 
              name="telefone" 
              value={formData.telefone} 
              onChange={handleChange}
              onBlur={handleBlur}
              placeholder="(00) 90000-0000" 
              className={inputClasses('telefone')} 
            />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
              E-mail
              {touched.email && errors.email && <span className="text-red-500 lowercase font-bold">Obrigatório</span>}
            </label>
            <input 
              type="email" 
              name="email" 
              value={formData.email} 
              onChange={handleChange}
              onBlur={handleBlur}
              placeholder="seu@email.com" 
              className={inputClasses('email')} 
            />
          </div>
        </div>

        {/* CAMPO DE FOTO COM PREVIEW MELHORADO E FEEDBACK DE ERRO */}
        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
            Foto do Documento (RG/CNH)
            {touched.documento && errors.documento && !fileError && <span className="text-red-500 lowercase font-bold">{errors.documento}</span>}
          </label>
          <div 
            onClick={() => !formData.documento && fileInputRef.current?.click()}
            className={`
              relative w-full h-32 rounded-3xl border-2 border-dashed flex items-center justify-center transition-all overflow-hidden
              ${fileError ? 'border-red-300 bg-red-50' : formData.documento ? 'border-emerald-400 bg-emerald-50' : touched.documento && errors.documento ? 'border-red-400 bg-red-50' : 'border-slate-100 bg-slate-50 hover:bg-white hover:border-[#001b3a]'}
              ${shakeField === 'documento' ? 'animate-shake border-red-400' : ''}
              ${!formData.documento ? 'cursor-pointer group' : ''}
            `}
          >
            {previewUrl ? (
              <div className="relative w-full h-full flex items-center justify-center p-2">
                <img src={previewUrl} alt="Preview Documento" className="h-full w-auto object-contain rounded-xl shadow-lg" />
                <button 
                  type="button"
                  onClick={clearFile}
                  className="absolute top-2 right-2 w-8 h-8 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-md text-red-500 hover:bg-red-500 hover:text-white transition-all"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
                <div className="absolute bottom-2 left-1/2 -translate-x-1/2 px-3 py-1 bg-[#001b3a]/80 backdrop-blur-md rounded-full">
                   <span className="text-[8px] font-black text-white uppercase tracking-widest">Documento Capturado</span>
                </div>
              </div>
            ) : (
              <div className="flex flex-col items-center gap-1">
                {fileError ? (
                  <>
                    <svg className="w-6 h-6 text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg>
                    <span className="text-[9px] font-black text-red-400 uppercase text-center px-4">{fileError}</span>
                  </>
                ) : (
                  <>
                    <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm mb-2 group-hover:scale-110 transition-transform">
                      <svg className="w-5 h-5 text-[#001b3a]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><circle cx="12" cy="13" r="3" strokeWidth="2.5" /></svg>
                    </div>
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider">Tocar para Abrir Câmera</span>
                  </>
                )}
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange}
              accept="image/*" 
              capture="environment" 
              className="hidden" 
            />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between">
            Revendedor
            {touched.revendedor && errors.revendedor && <span className="text-red-500 lowercase font-bold">{errors.revendedor}</span>}
          </label>
          <div className={`flex gap-2 p-1 rounded-2xl transition-colors ${touched.revendedor && errors.revendedor ? 'bg-red-50' : ''} ${shakeField === 'revendedor' ? 'animate-shake' : ''}`}>
            {['JF', 'Nogueira'].map((r) => (
              <button 
                key={r} type="button" 
                onClick={() => {
                  setFormData(p => ({...p, revendedor: r as any}));
                  setTouched(prev => ({...prev, revendedor: true}));
                  validateField('revendedor', r);
                }}
                className={`flex-1 py-4 rounded-xl border-2 font-black text-[10px] uppercase tracking-widest transition-all
                  ${formData.revendedor === r 
                    ? 'bg-[#001b3a] border-[#001b3a] text-white shadow-lg' 
                    : touched.revendedor && errors.revendedor 
                      ? 'border-red-200 bg-white text-red-300' 
                      : 'border-slate-50 bg-slate-50 text-slate-400 hover:border-slate-200'}
                `}
              >
                {r}
              </button>
            ))}
          </div>
        </div>

        <div className={`flex items-start gap-3 p-4 rounded-2xl transition-all border ${touched.aceite_privacidade && errors.aceite_privacidade ? 'bg-red-50 border-red-200 shadow-inner' : 'bg-slate-50 border-transparent'} ${shakeField === 'aceite_privacidade' ? 'animate-shake' : ''}`}>
          <input 
            type="checkbox" id="aceite" checked={formData.aceite_privacidade}
            onChange={(e) => {
              setFormData(p => ({...p, aceite_privacidade: e.target.checked}));
              setTouched(prev => ({...prev, aceite_privacidade: true}));
              validateField('aceite_privacidade', e.target.checked);
            }}
            className={`w-5 h-5 mt-0.5 rounded-lg border-slate-200 text-emerald-600 focus:ring-emerald-500 ${touched.aceite_privacidade && errors.aceite_privacidade ? 'border-red-400' : ''}`}
          />
          <label htmlFor="aceite" className="text-[9px] leading-tight text-slate-500 font-medium cursor-pointer">
            Concordo com a LGPD e autorizo o envio seguro dos meus dados para as Indústrias NB. <span className="text-red-500 font-black">*Obrigatório</span>
          </label>
        </div>

        <button 
          type="submit" 
          className="w-full py-5 bg-[#001b3a] text-white rounded-3xl font-black text-xs uppercase tracking-[0.25em] shadow-2xl shadow-blue-900/20 active:scale-95 transition-all"
        >
          Revisar e Enviar
        </button>
      </form>

      {(status === FormStatus.REVIEW || status === FormStatus.SUBMITTING) && (
        <LeadReview 
          data={formData} 
          onConfirm={() => {
            const handleFinalSubmit = async () => {
              if (status === FormStatus.SUBMITTING) return;
              setStatus(FormStatus.SUBMITTING);
              try {
                const response = await LeadService.submitLead(formData);
                if (response.success) {
                  onSuccess(formData);
                } else {
                  setStatus(FormStatus.ERROR);
                  // Feedback visual simples em caso de erro na etapa final
                  alert(response.message);
                }
              } catch {
                setStatus(FormStatus.ERROR);
                alert("Erro inesperado. Tente novamente.");
              }
            };
            handleFinalSubmit();
          }} 
          onEdit={() => setStatus(FormStatus.IDLE)} 
          isSubmitting={status === FormStatus.SUBMITTING}
        />
      )}
    </>
  );
};

