      formData.append("name", data.nome_completo);
      formData.append("email", data.email);
      // Campo extra para telefone (alguns painéis reconhecem automaticamente)
      formData.append("phone", data.telefone); 

      // 3. Conteúdo da Mensagem
      const messageBody = `
NOVO LEAD CAPTURADO
===================
Nome: ${data.nome_completo}
Email: ${data.email}
Telefone: ${data.telefone}
Revendedor Escolhido: ${data.revendedor}
Empresa: ${data.empresa || 'Particular'}

Link para WhatsApp: https://wa.me/55${data.telefone.replace(/\D/g, '')}

Status: Aceite de Privacidade Confirmado.
      `;
      formData.append("message", messageBody.trim());

      // 4. Anexo de Documento
      if (data.documento) {
        // Envio direto do arquivo sem renomeação complexa para evitar erros de encoding
        formData.append("attachment", data.documento);
      }

      // 5. Envio via Fetch Padrão
      // Removidos timeouts curtos e headers manuais para deixar o navegador gerenciar o Multipart
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData
      });

      const result = await response.json();

      if (response.ok && result.success) {
        return {
          success: true,
          message: "Cadastro enviado com sucesso!"
        };
      } else {
        console.error("Erro Web3Forms:", result);
        return {
          success: false,
          message: result.message || "Ocorreu um erro ao enviar o formulário."
        };
      }

    } catch (error) {
      console.error("Erro Crítico de Envio:", error);
      return {
        success: false,
        message: "Falha na conexão. Verifique sua internet."
      };
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  }
}

